class Solution:
    def minimumSubstringsInPartition(self, s: str) -> int:
        n = len(s)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(1, n + 1):
            for j in range(i):
                # Check if substring s[j:i] is balanced
                freq = {}
                for k in range(j, i):
                    freq[s[k]] = freq.get(s[k], 0) + 1
                if len(set(freq.values())) == 1:
                    dp[i] = min(dp[i], dp[j] + 1)

        return dp[n]
